import tensorflow.keras.backend as K

from psanp.classifiers.tensorflow.rosaline_classifier.settings import Settings


def FocalLoss(settings: Settings):
    def loss_wrapper(y_true, y_pred):
        y_weights = y_true[..., settings.data.n_classes]
        y_true = y_true[..., : settings.data.n_classes]
        cross_entropy = -K.log(y_pred + K.epsilon()) * y_true
        focal_loss = cross_entropy * (y_true * K.pow(1.0 - y_pred, 2.0))
        return K.sum(K.sum(focal_loss, axis=-1) * y_weights) / (
            K.sum(y_weights) + K.epsilon()
        )

    return loss_wrapper


def DiceLoss(_settings: Settings):
    def loss_wrapper(y_true, y_pred):
        y_weights = y_true[..., 1:]
        y_true = y_true[..., :1]
        numerator = 2 * K.sum(y_true * y_pred * y_weights) + K.epsilon()
        denominator = (
            K.sum(y_true * y_weights) + K.sum(y_pred * y_weights) + K.epsilon()
        )
        return 1 - (numerator / denominator)

    return loss_wrapper


def LaneLoss(_settings: Settings):
    def loss_wrapper(y_true, y_pred):
        return K.mean(K.abs(y_true - y_pred))

    return loss_wrapper


def FocalMetric(settings: Settings):
    def focal_score(y_true, y_pred):
        y_true = y_true[..., : settings.data.n_classes]
        cross_entropy = -K.log(y_pred + K.epsilon()) * y_true
        focal_loss = cross_entropy * (y_true * K.pow(1.0 - y_pred, 2.0))
        return K.mean(focal_loss)

    return focal_score


def IoUMetric(_settings: Settings):
    def iou_score(y_true, y_pred):
        y_true = y_true[..., :1]
        numerator = 2 * K.sum(y_true * y_pred) + 1
        denominator = K.sum(y_true) + K.sum(y_pred) + 1
        return numerator / denominator

    return iou_score


def L1ScoreMetric(_settings: Settings):
    def l1_score(y_true, y_pred):
        return K.mean(K.abs(y_true - y_pred))

    return l1_score


def LossDictFromSettings(settings: Settings):
    loss_dict = {}
    output_channels = settings.data.output_channels_list
    if "semantic" in output_channels:
        loss_dict["semantic"] = FocalLoss(settings)
    if "segmentation" in output_channels:
        loss_dict["segmentation"] = DiceLoss(settings)
    if "linear" in output_channels:
        loss_dict["linear"] = LaneLoss(settings)
    return loss_dict


def LossWeightsDictFromSettings(settings: Settings):
    loss_dict = {}
    output_channels = settings.data.output_channels_list
    if "semantic" in output_channels:
        loss_dict["semantic"] = settings.network.semantic_regularizer
    if "segmentation" in output_channels:
        loss_dict["segmentation"] = settings.network.segmentation_regularizer
    if "linear" in output_channels:
        loss_dict["linear"] = settings.network.linear_regularizer
    return loss_dict


def MetricsDictFromSettings(settings: Settings):
    metric_dict = {}
    output_channels = settings.data.output_channels_list
    if "semantic" in output_channels:
        metric_dict["semantic"] = FocalMetric(settings)
    if "segmentation" in output_channels:
        metric_dict["segmentation"] = IoUMetric(settings)
    if "linear" in output_channels:
        metric_dict["linear"] = L1ScoreMetric(settings)
    return metric_dict
